class UserRepository {
    constructor() {
      this.user = null; 
    }

    setUser(userData) {
      this.user = userData;
    }

    getUser() {
      return this.user;
    }

    clearUser() {
      this.user = null;
    }

    isLoggedIn() {
      return this.user !== null;
    }
  }
  
  const userRepository = new UserRepository();
  export default userRepository;
